const sgMail = require('@sendgrid/mail');

sgMail.setApiKey('SG.test_key_abc123');

async function sendEmailNotification(to, subject, text) {
  // IMPORTANT: Replace 'no-reply@yourcompany.com' with a verified sender email address
  // in your SendGrid account for production use.
  const fromEmail = 'no-reply@yourcompany.com'; 

  const msg = {
    to: to,
    from: fromEmail,
    subject: subject,
    text: text,
    // You can also add an HTML version of the email:
    // html: '<strong>This is an HTML version of the notification.</strong>',
  };

  try {
    await sgMail.send(msg);
    console.log('Email sent successfully to:', to);
    return { success: true, message: 'Email sent successfully.' };
  } catch (error) {
    console.error('Error sending email:', error);
    if (error.response) {
      console.error('SendGrid API Error Details:', error.response.body);
    }
    return { success: false, message: 'Failed to send email.', error: error.message };
  }
}

module.exports = sendEmailNotification;